class CallStats { final int latencyMs; final double packetLoss; final int bitrateKbps; final String codec; const CallStats({this.latencyMs = 0, this.packetLoss = 0, this.bitrateKbps = 128, this.codec = 'OPUS'}); String get qualityLabel { if (latencyMs < 100 && packetLoss < 0.02) return 'Excellent'; if (latencyMs < 200 && packetLoss < 0.05) return 'Good'; if (latencyMs < 500) return 'Fair'; return 'Poor'; } }